@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <!-- Stats Bar -->
    <div class="stats-bar d-flex gap-3 mb-3 p-3 bg-light rounded">
        <span><strong>Total:</strong> @tasks.Count</span>
        <span><strong>To Do:</strong> @GetColumnTasks("To Do").Count</span>
        <span><strong>In Progress:</strong> @GetColumnTasks("In Progress").Count</span>
        <span><strong>Done:</strong> @GetColumnTasks("Done").Count</span>
        <span class="text-danger"><strong>Overdue:</strong> @tasks.Count(t => t.DueDate < DateTime.Today)</span>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="d-flex gap-3">
        @foreach (var column in columns)
        {
            var columnTasks = GetFilteredColumnTasks(column);
            <div class="kanban-column flex-fill border rounded p-3" style="min-width: 250px;">
                <h4>@column <span class="badge bg-secondary">@columnTasks.Count</span></h4>

                @foreach (var task in columnTasks)
                {
                    <div class="card mb-2">
                        <div class="card-body p-2">
                            <h6 class="card-title mb-1">@task.Title</h6>
                            <p class="card-text mb-1 small text-muted">@task.Assignee</p>
                            <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                            <span class="small ms-2">@task.DueDate.ToString("MMM dd")</span>
                            <div class="mt-2">
                                @if (GetColumnIndex(column) > 0)
                                {
                                    <button class="btn btn-sm btn-outline-secondary me-1"
                                            @onclick="() => MoveTask(task, -1)">Move Left</button>
                                }
                                @if (GetColumnIndex(column) < columns.Length - 1)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTask(task, 1)">Move Right</button>
                                }
                            </div>
                        </div>
                    </div>
                }

                @if (activeFormColumn == column)
                {
                    <div class="card mb-2 border-primary">
                        <div class="card-body p-2">
                            <input type="text" class="form-control form-control-sm mb-1"
                                   placeholder="Title" @bind="newTitle" />
                            <input type="text" class="form-control form-control-sm mb-1"
                                   placeholder="Assignee" @bind="newAssignee" />
                            <select class="form-select form-select-sm mb-1" @bind="newPriority">
                                <option value="High">High</option>
                                <option value="Medium">Medium</option>
                                <option value="Low">Low</option>
                            </select>
                            <input type="date" class="form-control form-control-sm mb-1" @bind="newDueDate" />
                            <div class="d-flex gap-1">
                                <button class="btn btn-sm btn-primary" @onclick="SaveTask">Save</button>
                                <button class="btn btn-sm btn-secondary" @onclick="CancelForm">Cancel</button>
                            </div>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary w-100"
                            @onclick="() => ShowForm(column)">Add Task</button>
                }
            </div>
        }
    </div>
}

@code {
    private List<TaskItem> tasks = new();
    private bool isLoading = true;
    private string? errorMessage;
    private string searchText = string.Empty;

    private readonly string[] columns = { "To Do", "In Progress", "Done" };

    // Form state
    private string? activeFormColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status)
        => tasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status)
        => tasks.Where(t => t.Status == status &&
            (string.IsNullOrEmpty(searchText) || t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private int GetColumnIndex(string column) => Array.IndexOf(columns, column);

    private string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTask(TaskItem task, int direction)
    {
        var currentIndex = GetColumnIndex(task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            tasks = tasks.Select(t => t.Id == task.Id ? t with { Status = newStatus } : t).ToList();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private void ShowForm(string column)
    {
        activeFormColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today;
    }

    private void CancelForm() => activeFormColumn = null;

    private async Task SaveTask()
    {
        if (string.IsNullOrWhiteSpace(newTitle) || activeFormColumn is null) return;

        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
            tasks.Add(created);
            activeFormColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

